		CheckForStateChange(null, hediff);
		if (hediff.def.HasDefinedGraphicProperties || hediff.def.forceRenderTreeRecache)
		{
			pawn.Drawer.renderer.SetAllGraphicsDirty();
		}
		tmpRemovedHediffs.Add(hediff);
	}

